@Composable
fun TotalExpenditure(navController: NavController, viewModel: HomeScreenViewModel) {
    val monthlyTotal by viewModel.monthlyTotal.collectAsState()
    Box(
        modifier = Modifier
            .background(MaterialTheme.colorScheme.surface)
            .padding(16.dp),
        contentAlignment = Alignment.Center
    ) {
        Column (horizontalAlignment = Alignment.CenterHorizontally) {
            Text(
                text = "Total Expenditure",
                style = MaterialTheme.typography.titleLarge
            )
            Text(
                text = monthlyTotal.toString(),
                fontWeight = FontWeight.Bold
            )
        }
    }
}

@Composable
fun SyncButton(viewModel: HomeScreenViewModel) {
    val syncState by viewModel.syncState.collectAsState()
    val isSyncing = syncState == SyncRepositoryState.SYNCING

    Button(
        onClick = { viewModel.triggerSync() },
        enabled = !isSyncing,
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp)
            .height(48.dp)
    ) {
        if (isSyncing) {
            CircularProgressIndicator(
                modifier = Modifier.size(20.dp),
                strokeWidth = 2.dp,
                color = MaterialTheme.colorScheme.onPrimary
            )
            Spacer(modifier = Modifier.width(8.dp))
        }
        Icon(
            imageVector = Icons.Default.Sync,
            contentDescription = "Sync",
            modifier = Modifier.size(20.dp)
        )
        Spacer(modifier = Modifier.width(8.dp))
        Text(if (isSyncing) "Syncing..." else "Force Sync")
    }
}
